-- Bia Sell: Schema + Seed (banco zerado)
-- Fonte: doc/bia-sell.xlsx | Normalização: doc/relatorio-formatacao.md + doc/revisao.csv
--
-- Decisões de normalização:
--   • 192 pedidos (linha "Teste" ignorada conforme planilha)
--   • 17 datas sem ano → assumidas como 2025
--   • GRÁTIS → valor 0.00
--   • devolvido → status cancelado (observação preservada)
--   • status "t" → pendente (observação preservada)
--   • pix nubank / PIX - Banco Inter → pix
--   • pedidos sem cliente (nome vazio) → cliente_id NULL

-- 1. ENUMs
DO $$ BEGIN
  CREATE TYPE status_pedido AS ENUM ('pago', 'pendente', 'enviado', 'cancelado');
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN
  CREATE TYPE forma_pagamento AS ENUM ('pix', 'cartao', 'dinheiro', 'transferencia');
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- 2. Tabelas
CREATE TABLE IF NOT EXISTS produtos (
  id          UUID          DEFAULT gen_random_uuid() PRIMARY KEY,
  nome        TEXT          NOT NULL,
  preco       NUMERIC(10,2),
  descricao   TEXT,
  created_at  TIMESTAMPTZ   DEFAULT now()
);

CREATE TABLE IF NOT EXISTS clientes (
  id          UUID        DEFAULT gen_random_uuid() PRIMARY KEY,
  nome        TEXT        NOT NULL,
  instagram   TEXT,
  whatsapp    TEXT,
  endereco    TEXT,
  observacoes TEXT,
  created_at  TIMESTAMPTZ DEFAULT now()
);

CREATE TABLE IF NOT EXISTS pedidos (
  id              UUID            DEFAULT gen_random_uuid() PRIMARY KEY,
  cliente_id      UUID            REFERENCES clientes(id) ON DELETE SET NULL,
  produto_id      UUID            NOT NULL REFERENCES produtos(id) ON DELETE RESTRICT,
  quantidade      INTEGER         NOT NULL DEFAULT 1,
  valor           NUMERIC(10,2)   NOT NULL,
  status          status_pedido   NOT NULL DEFAULT 'pendente',
  data_pedido     DATE            NOT NULL,
  forma_pagamento forma_pagamento,
  observacoes     TEXT,
  created_at      TIMESTAMPTZ     DEFAULT now()
);

-- 3. RLS desabilitado (desenvolvimento)
ALTER TABLE produtos  DISABLE ROW LEVEL SECURITY;
ALTER TABLE clientes  DISABLE ROW LEVEL SECURITY;
ALTER TABLE pedidos   DISABLE ROW LEVEL SECURITY;

TRUNCATE TABLE pedidos, clientes, produtos RESTART IDENTITY CASCADE;

